    41→
    42→    private final long interval;
    43→
    44→    /** When merging we take the lowest of all fire timestamps as the new fire timestamp. */
    45→    private final ReducingStateDescriptor<Long> stateDesc =
    46→            new ReducingStateDescriptor<>("fire-time", new Min(), LongSerializer.INSTANCE);
    47→
    48→    private ContinuousEventTimeTrigger(long interval) {
    49→        this.interval = interval;
    50→    }
    51→
    52→    @Override
