    54→            throws Exception {
    55→
    56→        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
    57→            // if the watermark is already past the window fire immediately
    58→            return TriggerResult.FIRE;
    59→        } else {
    60→            ctx.registerEventTimeTimer(window.maxTimestamp());
    61→        }
    62→
    63→        ReducingState<Long> fireTimestampState = ctx.getPartitionedState(stateDesc);
    64→        if (fireTimestampState.get() == null) {
    65→            registerNextFireTimestamp(
    66→                    timestamp - (timestamp % interval), window, ctx, fireTimestampState);
    67→        }
    68→
    69→        return TriggerResult.CONTINUE;
    70→    }
